import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { WikiCard, type WikiArticle } from './WikiCard';

const mockArticleLoadingImage: WikiArticle = {
  title: 'JavaScript',
  displaytitle: 'JavaScript',
  extract: 'JavaScript is a versatile programming language used for web development.',
  pageid: 456,
  url: 'https://en.wikipedia.org/wiki/JavaScript',
  thumbnail: {
    source: 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/99/Unofficial_JavaScript_logo_2.svg/220px-Unofficial_JavaScript_logo_2.svg.png',
    width: 200,
    height: 200,
  },
};

const meta = {
  component: WikiCard,
  parameters: {
    layout: 'fullscreen',
  },
} satisfies Meta<typeof WikiCard>;

export default meta;
type Story = StoryObj<typeof meta>;

export const ImageLoading: Story = {
  args: {
    article: mockArticleLoadingImage,
  },
  play: async ({ canvas }) => {
    // Wait a bit for the page to render
    await new Promise(resolve => setTimeout(resolve, 100));

    // Check that the title is visible even while image is loading
    const title = canvas.getByRole('link', { name: /JavaScript/i });
    await expect(title).toBeVisible();

    // Check that extract is visible
    const extract = canvas.getByText(/versatile programming language/i);
    await expect(extract).toBeVisible();
  },
};

export const WithoutThumbnail: Story = {
  args: {
    article: {
      title: 'No Image Article',
      displaytitle: 'Article Without Image',
      extract: 'This article has no thumbnail image.',
      pageid: 789,
      url: 'https://en.wikipedia.org/wiki/Example',
      thumbnail: {
        source: '',
        width: 0,
        height: 0,
      },
    },
  },
  play: async ({ canvas }) => {
    // Check that the content is still visible without an image
    const title = canvas.getByRole('link', { name: /Article Without Image/i });
    await expect(title).toBeVisible();

    const extract = canvas.getByText(/no thumbnail image/i);
    await expect(extract).toBeVisible();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import Article from './Article';

const meta = {
  component: Article,
} satisfies Meta<typeof Article>;

export default meta;
type Story = StoryObj<typeof meta>;

export const EmptyTitle: Story = {
  args: {
    title: '',
    content: 'This article has no title.',
  },
  play: async ({ canvas }) => {
    // Check that content is still visible
    const content = canvas.getByText(/This article has no title/i);
    await expect(content).toBeVisible();
  },
};

export const VeryLongTitle: Story = {
  args: {
    title: 'This is an exceptionally long and detailed article title that contains multiple concepts and might wrap across several lines depending on the screen width and layout constraints',
    content: 'Article with very long title.',
  },
  play: async ({ canvas }) => {
    // Check that the long title is rendered
    const content = canvas.getByText(/This is an exceptionally long/i);
    await expect(content).toBeVisible();
  },
};

export const SpecialCharactersInTitle: Story = {
  args: {
    title: 'C++ & C# Programming: Best Practices & Examples',
    content: 'Learn about multiple programming languages and their practical applications.',
  },
  play: async ({ canvas }) => {
    // Check that special characters are properly rendered
    const title = canvas.getByRole('heading', { name: /C\+\+ & C#/i });
    await expect(title).toBeVisible();
  },
};

export const HTMLContent: Story = {
  args: {
    title: 'Article Title',
    content: 'Content with <strong>bold</strong> and <em>italic</em> text.',
  },
  play: async ({ canvas }) => {
    // Content should be rendered as-is (not interpreted as HTML)
    const content = canvas.getByText(/Content with <strong>bold/i);
    await expect(content).toBeVisible();
  },
};

export const MultilineContent: Story = {
  args: {
    title: 'Poetry Article',
    content: `Line one of a poem
    Line two of a poem
    Line three of a poem
    Line four of a poem`,
  },
  play: async ({ canvas }) => {
    // Check that multiline content is preserved
    const content = canvas.getByText(/Line one of a poem/i);
    await expect(content).toBeVisible();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, waitFor } from 'storybook/test';
import { LanguageSelector } from './LanguageSelector';

const meta = {
  component: LanguageSelector,
} satisfies Meta<typeof LanguageSelector>;

export default meta;
type Story = StoryObj<typeof meta>;

export const DropdownToggle: Story = {
  render: () => <LanguageSelector />,
  play: async ({ canvas, userEvent }) => {
    // Get the button
    const languageButton = canvas.getByRole('button', { name: /Language/i });
    await expect(languageButton).toBeVisible();

    // Click to open
    await userEvent.click(languageButton);

    // Verify dropdown is visible
    await waitFor(() => {
      const englishOption = canvas.getByRole('button', { name: /English/i });
      expect(englishOption).toBeVisible();
    });

    // Click to close
    await userEvent.click(languageButton);

    // The dropdown should no longer be visible
    await expect(canvas.queryByRole('button', { name: /English/i })).not.toBeInTheDocument();
  },
};

export const ScrollableLanguages: Story = {
  render: () => <LanguageSelector />,
  play: async ({ canvas, userEvent }) => {
    // Open dropdown
    const languageButton = canvas.getByRole('button', { name: /Language/i });
    await userEvent.click(languageButton);

    // Wait for dropdown to appear
    await waitFor(() => {
      const englishOption = canvas.getByRole('button', { name: /English/i });
      expect(englishOption).toBeVisible();
    });

    // Check that multiple languages are visible
    const spanishOption = canvas.getByRole('button', { name: /Español/i });
    await expect(spanishOption).toBeVisible();

    const frenchOption = canvas.getByRole('button', { name: /Français/i });
    await expect(frenchOption).toBeVisible();

    const germanOption = canvas.getByRole('button', { name: /Deutsch/i });
    await expect(germanOption).toBeVisible();
  },
};

export const LanguageFlags: Story = {
  render: () => <LanguageSelector />,
  play: async ({ canvas, userEvent }) => {
    // Open dropdown
    const languageButton = canvas.getByRole('button', { name: /Language/i });
    await userEvent.click(languageButton);

    // Wait for dropdown
    await waitFor(() => {
      const englishOption = canvas.getByRole('button', { name: /English/i });
      expect(englishOption).toBeVisible();
    });

    // Check that flag images are rendered
    const images = canvas.getAllByRole('img');
    await expect(images.length).toBeGreaterThan(0);

    // Check that at least one image has an alt text
    const flagImages = images.filter(img => img.alt && img.alt.length > 0);
    await expect(flagImages.length).toBeGreaterThan(0);
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import ArticleList from './ArticleList';
import type { ArticleProps } from '../types/ArticleProps';

const singleArticle: ArticleProps = {
  title: 'Single Article',
  content: 'This is the only article in the list.',
};

const twoArticles: ArticleProps[] = [
  {
    title: 'First Article',
    content: 'Content of the first article.',
  },
  {
    title: 'Second Article',
    content: 'Content of the second article.',
  },
];

const manyArticles: ArticleProps[] = Array.from({ length: 15 }, (_, i) => ({
  title: `Article ${i + 1}`,
  content: `This is article number ${i + 1} with some sample content.`,
  image: i % 3 === 0 ? 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/Camponotus_flavomarginatus_ant.jpg/320px-Camponotus_flavomarginatus_ant.jpg' : undefined,
}));

const meta = {
  component: ArticleList,
} satisfies Meta<typeof ArticleList>;

export default meta;
type Story = StoryObj<typeof meta>;

export const TwoArticles: Story = {
  args: {
    articles: twoArticles,
  },
  play: async ({ canvas }) => {
    // Check that both articles are rendered
    const first = canvas.getByText(/First Article/i);
    await expect(first).toBeVisible();

    const second = canvas.getByText(/Second Article/i);
    await expect(second).toBeVisible();
  },
};

export const ManyArticles: Story = {
  args: {
    articles: manyArticles,
  },
  play: async ({ canvas }) => {
    // Check that first article is visible
    const firstArticle = canvas.getByText(/Article 1/i);
    await expect(firstArticle).toBeVisible();

    // Check that some articles are rendered
    const thirdArticle = canvas.getByText(/Article 3/i);
    await expect(thirdArticle).toBeVisible();
  },
};

export const MixedWithAndWithoutImages: Story = {
  args: {
    articles: manyArticles,
  },
  play: async ({ canvas }) => {
    // Verify articles with and without images are both rendered
    const firstArticle = canvas.getByText(/Article 1/i);
    await expect(firstArticle).toBeVisible();

    const secondArticle = canvas.getByText(/Article 2/i);
    await expect(secondArticle).toBeVisible();
  },
};

export const KeyboardNavigation: Story = {
  args: {
    articles: twoArticles,
    onArticleSelect: (article: ArticleProps) => {
      console.log('Selected:', article.title);
    },
  },
  play: async ({ canvas, userEvent }) => {
    // Get the list items
    const listItems = canvas.getAllByRole('listitem');
    await expect(listItems.length).toBe(2);

    // First item should be focusable
    const firstItem = listItems[0];
    firstItem.focus();

    // Simulate space key press
    await userEvent.keyboard('{Enter}');

    // Article should be selectable
    await expect(firstItem).toBeInTheDocument();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, waitFor } from 'storybook/test';
import App from './App';

const meta = {
  component: App,
  parameters: {
    layout: 'fullscreen',
  },
} satisfies Meta<typeof App>;

export default meta;
type Story = StoryObj<typeof meta>;

// Mock fetch for Wikipedia API
globalThis.fetch = async (url: string | Request) => {
  const urlStr = typeof url === 'string' ? url : url.url;

  if (urlStr.includes('wikipedia.org')) {
    return new Response(JSON.stringify({
      batchcomplete: true,
      query: {
        pages: {
          '1': {
            pageid: 1,
            title: 'Article 1',
            thumbnail: {
              source: 'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a7/Camponotus_flavomarginatus_ant.jpg/320px-Camponotus_flavomarginatus_ant.jpg',
              width: 200,
              height: 200,
            },
            extract: 'First article description.',
            canonicalurl: 'https://en.wikipedia.org/wiki/Article1',
            varianttitles: { en: 'Article 1' },
          },
        },
      },
    }), { status: 200 });
  }

  return new Response(JSON.stringify({}), { status: 200 });
};

export const Navigation: Story = {
  render: () => <App />,
  play: async ({ canvas, userEvent }) => {
    // Click About button
    const aboutButton = canvas.getByRole('button', { name: /About/i });
    await userEvent.click(aboutButton);

    // Verify modal opened
    await waitFor(() => {
      const aboutTitle = canvas.getByText(/About WikiTok/i);
      expect(aboutTitle).toBeVisible();
    });

    // Close the modal by clicking the close button
    const closeButton = canvas.getAllByText('✕')[0];
    await userEvent.click(closeButton);

    // Modal should be closed
    await expect(canvas.queryByText(/About WikiTok/i)).not.toBeInTheDocument();
  },
};

export const EmptyLikes: Story = {
  beforeEach() {
    localStorage.setItem('likedArticles', '[]');
  },
  render: () => <App />,
  play: async ({ canvas, userEvent }) => {
    // Open likes
    const likesButton = canvas.getByRole('button', { name: /Likes/i });
    await userEvent.click(likesButton);

    // Check for empty state message
    await waitFor(() => {
      const emptyMessage = canvas.getByText(/No liked articles yet/i);
      expect(emptyMessage).toBeVisible();
    });

    // Export button should not be visible when no articles
    const exportButton = canvas.queryByRole('button', { name: /Export/i });
    await expect(exportButton).not.toBeInTheDocument();
  },
};

export const SearchLikes: Story = {
  beforeEach() {
    localStorage.setItem('likedArticles', JSON.stringify([
      {
        title: 'Python Programming',
        displaytitle: 'Python Programming',
        extract: 'Learn Python programming language.',
        pageid: 1,
        url: 'https://en.wikipedia.org/wiki/Python',
        thumbnail: {
          source: 'https://example.com/python.jpg',
          width: 200,
          height: 200,
        },
      },
      {
        title: 'JavaScript Guide',
        displaytitle: 'JavaScript Guide',
        extract: 'Master JavaScript for web development.',
        pageid: 2,
        url: 'https://en.wikipedia.org/wiki/JavaScript',
        thumbnail: {
          source: 'https://example.com/js.jpg',
          width: 200,
          height: 200,
        },
      },
    ]));
  },
  render: () => <App />,
  play: async ({ canvas, userEvent }) => {
    // Open likes
    const likesButton = canvas.getByRole('button', { name: /Likes/i });
    await userEvent.click(likesButton);

    // Wait for articles to appear
    await waitFor(() => {
      const pythonLink = canvas.getByRole('link', { name: /Python/i });
      expect(pythonLink).toBeVisible();
    });

    // Search for Python
    const searchInput = canvas.getByPlaceholderText(/Search liked articles/i);
    await userEvent.type(searchInput, 'Python');

    // Python should still be visible
    const pythonLink = canvas.getByRole('link', { name: /Python/i });
    await expect(pythonLink).toBeVisible();

    // JavaScript should not be visible
    await expect(canvas.queryByRole('link', { name: /JavaScript/i })).not.toBeInTheDocument();
  },
};

export const ExportFunctionality: Story = {
  beforeEach() {
    localStorage.setItem('likedArticles', JSON.stringify([
      {
        title: 'Test Article',
        displaytitle: 'Test Article',
        extract: 'Test article for export.',
        pageid: 1,
        url: 'https://en.wikipedia.org/wiki/Test',
        thumbnail: {
          source: 'https://example.com/test.jpg',
          width: 200,
          height: 200,
        },
      },
    ]));
  },
  render: () => <App />,
  play: async ({ canvas, userEvent }) => {
    // Open likes
    const likesButton = canvas.getByRole('button', { name: /Likes/i });
    await userEvent.click(likesButton);

    // Wait for content
    await waitFor(() => {
      const testLink = canvas.getByRole('link', { name: /Test Article/i });
      expect(testLink).toBeVisible();
    });

    // Export button should be visible
    const exportButton = canvas.getByRole('button', { name: /Export/i });
    await expect(exportButton).toBeVisible();

    // Export button should be clickable (we won't actually download)
    await expect(exportButton).toBeEnabled();
  },
};

